const item = $input.item.json;

if (!item.slides || !Array.isArray(item.slides)) {
  throw new Error('slides must be a non-empty array');
}
if (item.slides.length < 2) {
  throw new Error('Carousel requires at least 2 slides. Got: ' + item.slides.length);
}
if (item.slides.length > 10) {
  item.slides = item.slides.slice(0, 10);
}

item.slides.forEach(function(s, i) {
  if (!s.imageUrl) throw new Error('slides[' + i + '] missing imageUrl');
  if (!s.imageUrl.startsWith('https://')) {
    throw new Error('slides[' + i + '].imageUrl must be HTTPS');
  }
});

if (!item.caption) throw new Error('caption is required');

return { ...item };

const item = $input.item.json;

const collectionName = item.collectionName || 'New Collection';
const slides = item.slides;
const hook = item.hook || 'Swipe to see the full collection';
const cta = item.cta || 'Link in bio to shop';

const slideLines = slides.map(function(s, i) {
  var line = (i + 1) + '. ' + (s.title || 'Item ' + (i + 1));
  if (s.price) line = line + '  -  ' + (s.currency || '$') + s.price;
  return line;
}).join('\n');

var rawTags = item.hashtags || ['newcollection', 'shopnow', 'carousel'];
var hashtagBlock = rawTags.map(function(h) {
  return h.startsWith('#') ? h : '#' + h;
}).join(' ');

var captionParts = [
  collectionName + ' - ' + hook + ' ->',
  '',
  item.caption.trim(),
  '',
  'In this drop:',
  slideLines,
  '',
  cta,
  '',
  hashtagBlock
];

var fullCaption = captionParts.join('\n').trim();
if (fullCaption.length > 2200) {
  fullCaption = fullCaption.substring(0, 2196) + '...';
}

return {
  ...item,
  collectionName: collectionName,
  fullCaption: fullCaption,
  slideCount: slides.length
};

const item = $input.item.json;

const publicUrl = item.public_url || item.url || item.file_url || item.cdn_url || '';
if (!publicUrl) {
  throw new Error('Upload to URL returned no public URL. Keys: ' + JSON.stringify(Object.keys(item)));
}

const igUserId = $env.IG_USER_ID;
const accessToken = $env.IG_ACCESS_TOKEN;

const res = await fetch('https://graph.facebook.com/v19.0/' + igUserId + '/media', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    image_url: publicUrl,
    media_type: 'IMAGE',
    is_carousel_item: true,
    access_token: accessToken
  })
});

const data = await res.json();
if (data.error) {
  throw new Error('IG child container error: ' + data.error.message);
}

return {
  ...item,
  childContainerId: data.id,
  publicUrl: publicUrl
};

const allItems = $input.all();
const prepData = $('Code Build Caption1').first().json;

const childContainerIds = allItems
  .map(function(i) { return i.json.childContainerId; })
  .filter(Boolean);

if (childContainerIds.length < 2) {
  throw new Error('Need at least 2 child containers. Got: ' + childContainerIds.length);
}

return {
  childrenParam: childContainerIds.join(','),
  fullCaption: prepData.fullCaption,
  slideCount: prepData.slideCount,
  collectionName: prepData.collectionName,
  igUserId: $env.IG_USER_ID,
  accessToken: $env.IG_ACCESS_TOKEN
};

